/// Set to "pkl" to use the pkl CLI instead of the built-in pklr evaluator.
pub static HK_PKL_BACKEND: LazyLock<String> =
    LazyLock::new(|| var("HK_PKL_BACKEND").unwrap_or_else(|_| "pklr".to_string()));

static USE_PKL_R_BACKEND: LazyLock<bool> = LazyLock::new(|| match HK_PKL_BACKEND.as_str() {
    "pkl" => false,
    "pklr" => true,
    other => {
        warn!(
            "unrecognized HK_PKL_BACKEND value {other:?}; expected \"pkl\" or \"pklr\", defaulting to pklr"
        );
        true
    }
});

pub fn use_pklr_backend() -> bool {
    *USE_PKL_R_BACKEND
}

/// System's ARG_MAX value, memoized for performance
pub static ARG_MAX: LazyLock<usize> = LazyLock::new(|| {
    #[cfg(unix)]
    {
        // Try to get the system's ARG_MAX using sysconf
        // sysconf returns -1 on error or if the value is indeterminate
        unsafe {
            let value = libc::sysconf(libc::_SC_ARG_MAX);
            // Must check for -1 before casting to usize, as -1 would become a very large number
            if value != -1 && value > 0 {
                return value as usize;
            }
        }
    }

    // Fallback: Use a conservative 128KB limit that works on most systems
    // This is much smaller than typical ARG_MAX values (often 256KB-2MB)
    // but safe for portability
    128 * 1024
});

fn var_path(name: &str) -> Option<PathBuf> {
    var(name).map(PathBuf::from).ok()
}

fn var_csv(name: &str) -> Option<IndexSet<String>> {
    var(name)
        .map(|val| val.split(',').map(|s| s.trim().to_string()).collect())
        .ok()
}

fn var_log_level(name: &str) -> Option<log::LevelFilter> {
    var(name).ok().and_then(|level| level.parse().ok())
}

fn var_true(name: &str) -> bool {
    var(name)
        .map(|val| val.to_lowercase())
        .map(|val| val == "true" || val == "1")
        .unwrap_or(false)
}

fn var_false(name: &str) -> bool {
    var(name)
        .map(|val| val.to_lowercase())
        .map(|val| val == "false" || val == "0")
        .unwrap_or(false)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_arg_max_is_valid() {
        // ARG_MAX should be a reasonable value, not extremely large
        let arg_max = *ARG_MAX;

        // Should be at least the fallback value
        assert!(arg_max >= 128 * 1024, "ARG_MAX too small: {}", arg_max);

        // Should not be an unreasonably large value (like -1 cast to usize)
        // On most systems, ARG_MAX is between 128KB and 2MB
        // We'll use 10MB as an upper bound to catch the -1 bug
        assert!(
            arg_max <= 10 * 1024 * 1024,
            "ARG_MAX suspiciously large (possible -1 cast): {}",
            arg_max
        );
    }

    #[test]
    #[cfg(unix)]
    fn test_arg_max_unix_sysconf() {
        // On Unix systems, verify that sysconf returns a valid value or we use the fallback
        unsafe {
            let value = libc::sysconf(libc::_SC_ARG_MAX);
            if value == -1 {
                // If sysconf fails, we should use the fallback
                assert_eq!(*ARG_MAX, 128 * 1024);
            } else {
                // If sysconf succeeds, ARG_MAX should match it
                assert_eq!(*ARG_MAX, value as usize);
            }
        }
    }
}
//! Job batching to prevent ARG_MAX overflow.
//!
//! When passing large file lists to shell commands, the total argument length can exceed
//! the operating system's `ARG_MAX` limit, causing "Argument list too long" errors.
//!
//! This module renders the actual run command for each job and only splits jobs whose
//! rendered command exceeds the safe limit. Steps whose commands don't reference
//! `{{files}}` (or render to a small string for any other reason) are left as a
//! single job, even when the underlying file list is large.

use crate::env;
use crate::step_job::StepJob;
use crate::tera;
use std::path::PathBuf;
use std::sync::Arc;

use super::{ShellType, types::Step};

const CMD_COMMAND_LINE_LIMIT: usize = 8191;
const CMD_COMMAND_LINE_SAFE_LIMIT: usize = CMD_COMMAND_LINE_LIMIT / 2;

impl Step {
    fn auto_batch_safe_limit(&self) -> usize {
        match self.shell_type() {
            ShellType::Cmd => CMD_COMMAND_LINE_SAFE_LIMIT,
            _ => *env::ARG_MAX / 2,
        }
    }

    /// Estimates the size of the `{{files}}` template variable expansion.
    ///
    /// Used as a fallback when rendering the run command fails (e.g. the
    /// template references a variable not yet present in the context).
    pub(crate) fn estimate_files_string_size(&self, files: &[PathBuf]) -> usize {
        files
            .iter()
            .map(|f| {
                let path_str = f.to_str().unwrap_or("");
                // Worst-case quoted size: 2x + 2 (quotes), +1 for space separator
                path_str.len() * 2 + 2 + 1
            })
            .sum()
    }

    /// Render the run command for a hypothetical job containing `files` and return
    /// its byte length. Returns `None` if rendering fails (e.g. the template
    /// references a variable not in the context).
    fn render_run_command_size(
        &self,
        original_job: &StepJob,
        files: &[PathBuf],
        base_tctx: &tera::Context,
    ) -> Option<usize> {
        let run_cmd = if original_job.check_first {
            self.check_first_cmd().map(|cmd| cmd.script())
        } else {
            self.run_cmd(original_job.run_type)
        }?;
        let run = run_cmd.to_string();
        if run.trim().is_empty() {
            return None;
        }
        let run = if let Some(prefix) = &self.prefix {
            format!("{prefix} {run}")
        } else {
            run
        };

        let mut temp = StepJob::new(
            Arc::clone(&original_job.step),
            files.to_vec(),
            original_job.run_type,
        );
        temp.check_first = original_job.check_first;
        if let Some(wi) = original_job.workspace_indicator() {
            temp = temp.with_workspace_indicator(wi.clone());
        }
        let tctx = temp.tctx(base_tctx);
        tera::render(&run, &tctx).ok().map(|s| s.len())
    }

    /// Automatically batch jobs whose rendered run command would exceed the safe ARG_MAX limit.
    ///
    /// Uses 50% of the effective command-line limit as the safety margin
    /// (accounts for env vars, shell wrappers, and the command itself).
    /// Renders the actual run command with each candidate file subset; if the rendered command
    /// fits, no batching is performed. Otherwise binary-searches the largest batch size whose
    /// rendered command still fits.
    ///
    /// If rendering fails for any reason, falls back to estimating the size of the quoted
    /// file-list expansion — preserves the previous (purely size-based) behavior as a safety net.
    pub(crate) fn auto_batch_jobs(
        &self,
        jobs: Vec<StepJob>,
        base_tctx: &tera::Context,
    ) -> Vec<StepJob> {
        if self.stdin.is_some() {
            // stdin path doesn't pass files via argv; never auto-batch
            return jobs;
        }

        let safe_limit = self.auto_batch_safe_limit();
        let mut batched_jobs = Vec::with_capacity(jobs.len());

        for job in jobs {
            if job.skip_reason.is_some() || job.files.len() <= 1 {
                batched_jobs.push(job);
                continue;
            }

            // Try render-based sizing first; fall back to byte estimation on render failure.
            let full_size = self
                .render_run_command_size(&job, &job.files, base_tctx)
                .unwrap_or_else(|| self.estimate_files_string_size(&job.files));

            if full_size <= safe_limit {
                batched_jobs.push(job);
                continue;
            }

            debug!(
                "{}: auto-batching {} files (rendered size: {} bytes, limit: {} bytes)",
                self.name,
                job.files.len(),
                full_size,
                safe_limit
            );

            // Binary search the largest batch size whose rendered command fits.
            let mut low = 1;
            let mut high = job.files.len();
            while low < high {
                let mid = (low + high).div_ceil(2);
                let test_size = self
                    .render_run_command_size(&job, &job.files[..mid], base_tctx)
                    .unwrap_or_else(|| self.estimate_files_string_size(&job.files[..mid]));
                if test_size <= safe_limit {
                    low = mid;
                } else {
                    high = mid - 1;
                }
            }
            let batch_size = low.max(1);

            debug!(
                "{}: using batch size of {} files per batch",
                self.name, batch_size
            );

            for chunk in job.files.chunks(batch_size) {
                let mut new_job = StepJob::new(Arc::clone(&job.step), chunk.to_vec(), job.run_type);
                // Preserve job-level state that isn't reconstructed by StepJob::new.
                new_job.check_first = job.check_first;
                new_job.skip_reason = job.skip_reason.clone();
                if let Some(wi) = job.workspace_indicator() {
                    new_job = new_job.with_workspace_indicator(wi.clone());
                }
                batched_jobs.push(new_job);
            }
        }

        batched_jobs
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::step::RunType;
    use crate::step_job::StepJob;

    #[test]
    fn cmd_shell_uses_cmd_command_line_limit() {
        let step = Step {
            shell: Some("cmd.exe".parse().unwrap()),
            ..Default::default()
        };

        assert_eq!(step.auto_batch_safe_limit(), CMD_COMMAND_LINE_SAFE_LIMIT);
    }

    #[test]
    fn non_cmd_shell_uses_arg_max_limit() {
        let step = Step {
            shell: Some("sh".parse().unwrap()),
            ..Default::default()
        };

        assert_eq!(step.auto_batch_safe_limit(), *env::ARG_MAX / 2);
    }

    #[test]
    fn cmd_shell_auto_batches_below_unix_arg_max() {
        let step = Step {
            name: "test".to_string(),
            shell: Some("cmd.exe".parse().unwrap()),
            check: Some("echo {{files}}".parse().unwrap()),
            ..Default::default()
        };
        let files = (0..400)
            .map(|i| {
                PathBuf::from(format!(
                    "directory/with/a/long/path/file_with_a_long_name_{i}.txt"
                ))
            })
            .collect();
        let job = StepJob::new(Arc::new(step.clone()), files, RunType::Check);

        let jobs = step.auto_batch_jobs(vec![job], &tera::Context::default());

        assert!(jobs.len() > 1);
    }
}

