use indexmap::IndexMap;
use std::path::{Path, PathBuf};
use std::time::Instant;

use crate::{
    Result, git_util,
    step::RunType,
    step::Step,
    step_test::{RunKind, StepTest},
    tera,
};
use ensembler::CmdLineRunner;

#[allow(unused)]
pub struct TestResult {
    pub step: String,
    pub name: String,
    pub ok: bool,
    pub stdout: String,
    pub stderr: String,
    pub code: i32,
    pub duration_ms: u128,
    pub reasons: Vec<String>,
}

async fn execute_cmd(
    step: &Step,
    tctx: &tera::Context,
    base_dir: &Path,
    test: &StepTest,
    cmd_str: &str,
    stdin: &Option<String>,
) -> Result<(String, String, i32)> {
    let mut runner = if let Some(shell) = &step.shell {
        let shell = shell.to_string();
        let mut parts = shell.split_whitespace();
        let bin = parts.next().unwrap_or("sh");
        CmdLineRunner::new(bin).args(parts)
    } else {
        CmdLineRunner::new("sh").arg("-o").arg("errexit").arg("-c")
    };
    if let Some(stdin) = stdin {
        let rendered_stdin = tera::render(stdin, tctx)?;
        runner = runner.stdin_string(rendered_stdin);
    }
    runner = runner.arg(cmd_str).current_dir(base_dir);
    for (k, v) in &step.env {
        let v = tera::render(v, tctx)?;
        runner = runner.env(k, v);
    }
    for (k, v) in &test.env {
        runner = runner.env(k, v);
    }
    let result = runner.execute().await;
    let (stdout, stderr, code) = match result {
        Ok(r) => (r.stdout, r.stderr, r.status.code().unwrap_or(0)),
        Err(e) => {
            if let ensembler::Error::ScriptFailed(tuple) = &e {
                let r = &tuple.3;
                (
                    r.stdout.clone(),
                    r.stderr.clone(),
                    r.status.code().unwrap_or(1),
                )
            } else {
                return Err(e.into());
            }
        }
    };
    Ok((stdout, stderr, code))
}

fn check_exit_code(actual: i32, expected: i32) -> Option<String> {
    if actual != expected {
        Some(format!("exit code {} != expected {}", actual, expected))
    } else {
        None
    }
}

fn check_after_fail(after_fail: &Option<(i32, String, String)>) -> Option<String> {
    if let Some((code, _, _)) = after_fail {
        Some(format!("after failed with code {}", code))
    } else {
        None
    }
}

fn check_stdout_contains(stdout: &str, expected: &Option<String>) -> Option<String> {
    if let Some(needle) = expected
        && !stdout.contains(needle)
    {
        return Some(format!("stdout missing: {}", needle));
    }
    None
}

fn check_stderr_contains(stderr: &str, expected: &Option<String>) -> Option<String> {
    if let Some(needle) = expected
        && !stderr.contains(needle)
    {
        return Some(format!("stderr missing: {}", needle));
    }
    None
}

fn check_file_contents(
    expected_files: &IndexMap<String, String>,
    tctx: &tera::Context,
    base_dir: &Path,
) -> Result<Vec<String>> {
    let mut reasons = Vec::new();
    for (rel, expected) in expected_files {
        let rendered = tera::render(rel, tctx)?;
        let path = {
            let p = PathBuf::from(&rendered);
            if p.is_absolute() {
                p
            } else {
                base_dir.join(&rendered)
            }
        };
        let contents = xx::file::read_to_string(&path)?;
        if contents != *expected {
            let udiff = crate::diff::render_unified_diff(expected, &contents, "expected", "actual");
            reasons.push(format!("file mismatch: {}\n{}", path.display(), udiff));
        }
    }
    Ok(reasons)
}

pub async fn run_test_named(step: &Step, name: &str, test: &StepTest) -> Result<TestResult> {
    let started_at = Instant::now();
    let tmp = tempfile::tempdir().unwrap();
    let sandbox = tmp
        .path()
        .canonicalize()
        .unwrap_or_else(|_| tmp.path().to_path_buf());
    let mut tctx = crate::tera::Context::default();
    tctx.insert("tmp", &sandbox.display().to_string());

    let rendered_write: IndexMap<PathBuf, &String> = test
        .write
        .iter()
        .map(|(f, contents)| {
            (
                tera::render(f, &tctx).unwrap_or_else(|_| f.clone()).into(),
                contents,
            )
        })
        .collect();
    let mut files: Vec<PathBuf> = match &test.files {
        Some(files) => files
            .iter()
            .map(|f| tera::render(f, &tctx).unwrap_or_else(|_| f.clone()))
            .map(PathBuf::from)
            .collect(),
        None => rendered_write.keys().cloned().collect(),
    };

    // Decide whether to use a sandbox based on the explicit `tmpdir` setting,
    // or auto-detect based on whether files reference {{tmp}}.
    // If not using sandbox, operate from the project root instead.
    let uses_sandbox = test
        .tmpdir
        .unwrap_or_else(|| files.iter().any(|p| p.starts_with(&sandbox)));

    if test.files.is_none() {
        files = step.filter_files(&files)?;
    }

    let base_dir = if uses_sandbox {
        sandbox.to_path_buf()
    } else {
        git_util::find_work_tree_root()
    };
    if let Some(fixture) = &test.fixture {
        let src = PathBuf::from(fixture);
        xx::file::copy_dir_all(&src, &base_dir)?;
    }
    for (p, contents) in &rendered_write {
        let path = {
            if p.is_absolute() {
                p.clone()
            } else {
                base_dir.join(p)
            }
        };
        xx::file::write(&path, contents)?;
    }

    tctx.with_files(step.shell_type(), &files);
    let abs_files = files
        .clone()
        .into_iter()
        .map(|f| base_dir.join(&f))
        .collect::<Vec<_>>();

    // Handle `workspace_indicator`
    if let Some(workspaces) = step.workspaces_for_files(&abs_files)? {
        let workspace_indicator = match workspaces.len() {
            0 => eyre::bail!("{}: no workspace_indicator found for files", step.name,),
            1 => workspaces.into_iter().next().unwrap(),
            n => eyre::bail!(
                "{}: expected exactly one workspace_indicator, found {}: {:?}",
                step.name,
                n,
                workspaces
            ),
        };

        tctx.with_workspace_indicator(&workspace_indicator);
        let workspace_dir = workspace_indicator
            .parent()
            .filter(|p| !p.as_os_str().is_empty())
            .unwrap_or(std::path::Path::new("."));
        tctx.with_workspace_files(step.shell_type(), workspace_dir, &files);
    }

    // Render command
    let run_type = match test.run {
        RunKind::Fix => RunType::Fix,
        RunKind::Check => RunType::Check,
    };

    let Some(mut run) = step
        .run_cmd(run_type)
        .map(|s| s.to_string())
        .filter(|s| !s.trim().is_empty())
    else {
        eyre::bail!("{}: no command for test", step.name);
    };
    if let Some(prefix) = &step.prefix {
        run = format!("{prefix} {run}");
    }
    let run = tera::render(&run, &tctx)?;

    // Run pre-command (before)
    let mut before_stdout = String::new();
    let mut before_stderr = String::new();
    if let Some(cmd_str) = &test.before {
        let rendered = tera::render(cmd_str, &tctx)?;
        let (stdout, stderr, code) =
            execute_cmd(step, &tctx, &base_dir, test, &rendered, &None).await?;
        before_stdout = stdout.clone();
        before_stderr = stderr.clone();
        if code != 0 {
            return Ok(TestResult {
                step: step.name.clone(),
                name: name.to_string(),
                ok: false,
                stdout,
                stderr,
                code,
                duration_ms: started_at.elapsed().as_millis(),
                reasons: vec![format!("before failed with code {}", code)],
            });
        }
    }

//! Output capture and fix suggestions.
//!
//! This module handles:
//! - Saving command output for the end-of-run summary
//! - Generating helpful "to fix, run:" suggestions when checks fail

use crate::step_context::StepContext;
use crate::step_job::StepJob;
use crate::tera;
use crate::ui::style;
use std::sync::Arc;

use super::types::{OutputSummary, RunType, Step};

impl Step {
    /// Save command output for the end-of-run summary.
    ///
    /// Based on the step's `output_summary` setting, captures the appropriate
    /// output (stderr, stdout, combined, or none) to display after all steps complete.
    ///
    /// Skips saving output for check_first checks that failed (since they'll be
    /// followed by a fix that will have its own output).
    ///
    /// # Arguments
    ///
    /// * `ctx` - The step context
    /// * `job` - The current job
    /// * `stdout` - Command stdout
    /// * `stderr` - Command stderr
    /// * `combined` - Interleaved stdout/stderr
    /// * `is_failure` - Whether the command failed
    pub(crate) fn save_output_summary(
        &self,
        ctx: &StepContext,
        job: &StepJob,
        stdout: &str,
        stderr: &str,
        combined: &str,
        is_failure: bool,
    ) {
        // Only skip if this is a check_first check that FAILED (will be followed by a fix)
        // If the check passed, we want to show its output since no fix will run
        let is_check_first_check_that_failed =
            job.check_first && matches!(job.run_type, RunType::Check) && is_failure;
        if is_check_first_check_that_failed {
            return;
        }

        if is_failure {
            ctx.hook_ctx.mark_step_failed(&self.name);
        }

        // On failure, use combined output so diagnostic messages are never
        // lost regardless of which stream the tool writes to — but keep
        // the configured label so tests/users see the expected header.
        // If the step explicitly opted out with `output_summary = "hide"`,
        // respect that even on failure.
        if is_failure && self.output_summary != OutputSummary::Hide {
            ctx.hook_ctx
                .append_step_output(&self.name, self.output_summary.clone(), combined)
        } else {
            match self.output_summary {
                OutputSummary::Stderr => {
                    ctx.hook_ctx
                        .append_step_output(&self.name, OutputSummary::Stderr, stderr)
                }
                OutputSummary::Stdout => {
                    ctx.hook_ctx
                        .append_step_output(&self.name, OutputSummary::Stdout, stdout)
                }
                OutputSummary::Combined => {
                    ctx.hook_ctx
                        .append_step_output(&self.name, OutputSummary::Combined, combined)
                }
                OutputSummary::Hide => {}
            }
        }
    }

    /// Collect a helpful fix suggestion when a check fails.
    ///
    /// When running in check mode and a step fails, this generates a message
    /// like "To fix, run: eslint --fix src/file.ts" to help the user.
    ///
    /// For multi-line commands, suggests `hk fix -S <step>` instead of the
    /// full command.
    ///
    /// # Arguments
    ///
    /// * `ctx` - The step context
    /// * `job` - The current job
    /// * `run_cmd` - Optional command that produced cmd_result
    /// * `cmd_result` - Optional command result (for filtering files from check output)
    pub(crate) fn collect_fix_suggestion(
        &self,
        ctx: &StepContext,
        job: &StepJob,
        run_cmd: Option<&super::types::Command>,
        cmd_result: Option<&ensembler::CmdResult>,
    ) {
        // Only suggest fixes when the entire hook run is in check mode,
        // not when an individual job temporarily runs a check (e.g., check_first during a fix run)
        if !matches!(ctx.hook_ctx.run_type, RunType::Check) || self.fix.is_none() {
            return;
        }
        // Prefer filtering files when the failed check command can identify
        // the files needing fixes.
        let mut suggest_files = job.files.clone();
        if let (Some(run_cmd), Some(result)) = (run_cmd, cmd_result) {
            let (files, parser) = if Some(run_cmd) == self.check_diff.as_ref() {
                let (files, _extras) =
                    self.filter_files_from_check_diff(&job.files, &result.stdout);
                (files, Some("check_diff"))
            } else if Some(run_cmd) == self.check_list_files.as_ref() {
                let (files, _extras) =
                    self.filter_files_from_check_list(&job.files, &result.stdout);
                (files, Some("check_list_files"))
            } else {
                (vec![], None)
            };
            if !files.is_empty() {
                suggest_files = files;
            } else if let Some(parser) = parser {
                debug!(
                    "{self}: {parser} output did not match any job files; suggesting all job files"
                );
            }
        }
        // Build a minimal context based on the suggested files, honoring dir/workspace
        let temp_job = StepJob::new(Arc::new(self.clone()), suggest_files, RunType::Fix);
        let suggest_ctx = temp_job.tctx(&ctx.hook_ctx.tctx);
        if let Some(fix_cmd) = self
            .run_cmd(RunType::Fix)
            .filter(|command| !command.is_empty())
        {
            if let Ok(rendered) = fix_cmd.render(&suggest_ctx, self.prefix.as_deref()) {
                let rendered = rendered.display(self.shell_type());
                let is_multi_line = rendered.contains('\n');
                if is_multi_line {
                    // Too long to inline; suggest hk fix with step filter
                    let step_flag = format!("-S {}", &self.name);
                    let cmd = format!(
                        "To fix, run: {}",
                        style::edim(format!("hk fix {}", step_flag))
                    );
                    ctx.hook_ctx.add_fix_suggestion(cmd);
                } else {
                    let cmd = format!("To fix, run: {}", style::edim(rendered));
                    ctx.hook_ctx.add_fix_suggestion(cmd);
                }
            }
        }
    }
}
