//! Core type definitions for step configuration.
//!
//! This module contains the fundamental types used to define and configure steps:
//! - [`Step`] - The main configuration struct for a linting/formatting step
//! - [`FileSelector`] - A positive file selector used by `match_any`
//! - [`Pattern`] - File matching patterns (globs or regex)
//! - [`Command`] - Shell scripts or structured argument vectors
//! - [`Script`] - Platform-specific shell scripts
//! - [`RunType`] - Whether to run in check or fix mode
//! - [`OutputSummary`] - How to capture and display command output

use crate::{Result, step_test::StepTest, tera};
use indexmap::IndexMap;
use serde::{Deserialize, Serialize};
use serde_with::{DisplayFromStr, PickFirst, serde_as};
use std::{fmt, fmt::Display, path::PathBuf, str::FromStr};

/// A file matching pattern that can be either glob patterns or a regex.
///
/// Patterns are used to filter which files a step should operate on.
///
/// # Variants
///
/// * `Regex` - A regular expression pattern for complex matching
/// * `Globs` - One or more glob patterns (e.g., `*.rs`, `**/*.ts`)
#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
#[serde(untagged)]
pub enum Pattern {
    /// A regex pattern with explicit type marker
    Regex {
        _type: String,
        /// The regex pattern string
        pattern: String,
    },
    /// One or more glob patterns
    Globs(Vec<String>),
}

impl Pattern {
    pub fn is_empty(&self) -> bool {
        match self {
            Pattern::Regex { .. } => false,
            Pattern::Globs(globs) => globs.is_empty(),
        }
    }
}

impl<'de> Deserialize<'de> for Pattern {
    fn deserialize<D>(deserializer: D) -> std::result::Result<Self, D::Error>
    where
        D: serde::Deserializer<'de>,
    {
        use serde::de::Error;
        use serde_json::Value;

        let value = Value::deserialize(deserializer)?;

        // Check if it's a regex object with _type field
        if let Value::Object(ref map) = value
            && let Some(Value::String(type_str)) = map.get("_type")
            && type_str == "regex"
            && let Some(Value::String(pattern)) = map.get("pattern")
        {
            return Ok(Pattern::Regex {
                _type: "regex".to_string(),
                pattern: pattern.clone(),
            });
        }

        // Try to deserialize as a string
        if let Value::String(s) = value {
            return Ok(Pattern::Globs(vec![s]));
        }

        // Try to deserialize as array of strings
        if let Value::Array(arr) = value {
            let globs: Result<Vec<String>, _> = arr
                .into_iter()
                .map(|v| {
                    if let Value::String(s) = v {
                        Ok(s)
                    } else {
                        Err(D::Error::custom("array elements must be strings"))
                    }
                })
                .collect();
            return Ok(Pattern::Globs(globs?));
        }

        Err(D::Error::custom(
            "expected regex object, string, or array of strings",
        ))
    }
}

/// A positive file-selection clause.
///
/// Glob and type filters within one selector use AND semantics. Multiple
/// selectors in [`Step::match_any`] use OR semantics.
#[derive(Debug, Default, Clone, PartialEq, Eq, Deserialize, Serialize)]
#[serde(rename_all = "snake_case")]
#[cfg_attr(debug_assertions, serde(deny_unknown_fields))]
pub struct FileSelector {
    /// File matching pattern (globs or regex)
    #[serde(default)]
    pub glob: Option<Pattern>,

    /// File types to match
    #[serde(default)]
    pub types: Option<Vec<String>>,
}

impl FileSelector {
    pub fn is_empty(&self) -> bool {
        self.glob.as_ref().is_none_or(Pattern::is_empty)
            && self.types.as_ref().is_none_or(Vec::is_empty)
    }
}

/// A step configuration that defines a linting or formatting task.
///
/// Steps are the core building blocks of hk. Each step defines:
/// - What files to operate on (via globs, types, excludes)
/// - What commands to run (check, fix, check_diff, check_list_files)
/// - How to run them (shell, environment, working directory)
/// - Dependencies and execution constraints
///
/// # Example (in hk.pkl)
///
/// ```pkl
/// ["eslint"] {
///     glob = "*.{js,ts}"
///     check = "eslint {{files}}"
///     fix = "eslint --fix {{files}}"
/// }
/// ```
#[serde_as]
#[derive(Debug, Default, Clone, PartialEq, Eq, Deserialize, Serialize)]
#[serde(rename_all = "snake_case")]
#[cfg_attr(debug_assertions, serde(deny_unknown_fields))]
pub struct Step {
    /// Internal type marker (used by Pkl)
    #[serde(skip_serializing_if = "Option::is_none")]
    pub _type: Option<String>,

    /// Category for documentation grouping (e.g., "JavaScript/TypeScript", "Python", "Rust")
    #[serde(skip_serializing_if = "Option::is_none")]
    pub category: Option<String>,

    /// Human-readable description of the step for documentation
    #[serde(skip_serializing_if = "Option::is_none")]
    pub description: Option<String>,

    /// The step name (set during initialization)
    #[serde(default)]
    pub name: String,

    /// Profiles that enable/disable this step (prefix with `!` to disable)
    pub profiles: Option<Vec<String>>,

    /// File matching pattern (globs or regex)
    #[serde(default)]
    pub glob: Option<Pattern>,

    /// File types to match (e.g., `["rust", "toml"]`)
    #[serde(default)]
    pub types: Option<Vec<String>>,

    /// Alternative positive file selectors, combined with OR semantics
    #[serde(default)]
    pub match_any: Option<Vec<FileSelector>>,

    /// Whether this step requires interactive terminal input
    #[serde(default)]
    pub interactive: bool,

    /// Content to pipe to the command's stdin
    pub stdin: Option<String>,

    /// Environment variables that must be set for this step to run
    #[serde(default)]
    pub required: Vec<String>,

    /// Steps that must complete before this one runs
    #[serde(default)]
    pub depends: Vec<String>,

    /// Custom shell to use (default: `sh -o errexit -c`)
    #[serde_as(as = "Option<PickFirst<(_, DisplayFromStr)>>")]
    pub shell: Option<Script>,

    /// Command to check for issues (exit non-zero if issues found)
    #[serde_as(as = "Option<PickFirst<(_, DisplayFromStr)>>")]
    pub check: Option<Command>,

    /// Command that outputs a list of files needing fixes (one per line)
    #[serde_as(as = "Option<PickFirst<(_, DisplayFromStr)>>")]
    pub check_list_files: Option<Command>,

    /// Command that outputs a unified diff of needed changes
    #[serde_as(as = "Option<PickFirst<(_, DisplayFromStr)>>")]
    pub check_diff: Option<Command>,

    /// Command to fix issues
    #[serde_as(as = "Option<PickFirst<(_, DisplayFromStr)>>")]
    pub fix: Option<Command>,

    /// File that indicates workspace roots (e.g., `Cargo.toml` for Rust)
    pub workspace_indicator: Option<String>,

    /// Prefix to prepend to all commands
    pub prefix: Option<String>,

    /// Working directory for commands (relative to repo root)
    pub dir: Option<String>,

    /// Expression that must evaluate to true for step job to run
    #[serde(rename = "condition")]
    pub job_condition: Option<String>,

    /// Expression that must evaluate to true for step to run
    pub step_condition: Option<String>,

    /// Run check command before fix to identify files needing changes
    #[serde(default)]
    pub check_first: bool,

    /// Split files across multiple parallel jobs
    #[serde(default)]
    pub batch: bool,

    /// Allow overwriting files being processed by other steps
    #[serde(default)]
    pub stomp: bool,

    /// Environment variables to set
    #[serde(default)]
    pub env: IndexMap<String, String>,

    /// Glob patterns for files to stage after fixing
    pub stage: Option<Vec<String>>,

    /// Patterns to exclude from matching
    pub exclude: Option<Pattern>,

    /// Run this step alone (not in parallel with others)
    #[serde(default)]
    pub exclusive: bool,

    /// Whether to include binary files (default: false)
    #[serde(default)]
    pub allow_binary: bool,

    /// Whether to include symbolic links (default: false)
    #[serde(default)]
    pub allow_symlinks: bool,

    /// Root directory override
    pub root: Option<PathBuf>,

//! Job batching to prevent ARG_MAX overflow.
//!
//! When passing large file lists to shell commands, the total argument length can exceed
//! the operating system's `ARG_MAX` limit, causing "Argument list too long" errors.
//!
//! This module renders the actual run command for each job and only splits jobs whose
//! rendered command exceeds the safe limit. Steps whose commands don't reference
//! `{{files}}` (or render to a small string for any other reason) are left as a
//! single job, even when the underlying file list is large.

use crate::env;
use crate::step_job::StepJob;
use crate::tera;
use eyre::{Result, bail};
use std::path::PathBuf;
use std::sync::Arc;

use super::{ShellType, types::{Command, Step}};

const CMD_COMMAND_LINE_LIMIT: usize = 8191;
const CMD_COMMAND_LINE_SAFE_LIMIT: usize = CMD_COMMAND_LINE_LIMIT / 2;
const WINDOWS_CREATE_PROCESS_LIMIT: usize = 32767;
const WINDOWS_CREATE_PROCESS_SAFE_LIMIT: usize = WINDOWS_CREATE_PROCESS_LIMIT / 2;
#[cfg(target_os = "linux")]
// Linux limits each argv/envp string to 32 pages, independently of ARG_MAX.
const LINUX_MAX_ARG_STRLEN_PAGES: usize = 32;

#[cfg(target_os = "linux")]
fn platform_max_arg_strlen() -> Option<usize> {
    let page_size = unsafe { libc::sysconf(libc::_SC_PAGESIZE) };
    if page_size > 0 {
        Some((page_size as usize).saturating_mul(LINUX_MAX_ARG_STRLEN_PAGES))
    } else {
        Some(128 * 1024)
    }
}

#[cfg(not(target_os = "linux"))]
fn platform_max_arg_strlen() -> Option<usize> {
    None
}

fn shell_command_safe_limit(arg_max: usize, max_arg_strlen: Option<usize>) -> usize {
    let aggregate_limit = arg_max / 2;
    match max_arg_strlen {
        // execve includes the terminating NUL in MAX_ARG_STRLEN.
        Some(max_arg_strlen) => aggregate_limit.min(max_arg_strlen.saturating_sub(1)),
        None => aggregate_limit,
    }
}

impl Step {
    fn auto_batch_safe_limit(&self, command: &Command) -> usize {
        if command.is_argv() {
            return if cfg!(windows) {
                WINDOWS_CREATE_PROCESS_SAFE_LIMIT
            } else {
                *env::ARG_MAX / 2
            };
        }
        match self.shell_type() {
            ShellType::Cmd => CMD_COMMAND_LINE_SAFE_LIMIT,
            _ => shell_command_safe_limit(*env::ARG_MAX, platform_max_arg_strlen()),
        }
    }

    /// Estimates the size of the `{{files}}` template variable expansion.
    ///
    /// Used as a fallback when rendering the run command fails (e.g. the
    /// template references a variable not yet present in the context).
    pub(crate) fn estimate_files_string_size(&self, files: &[PathBuf]) -> usize {
        files
            .iter()
            .map(|f| {
                let path_str = f.to_str().unwrap_or("");
                // Worst-case quoted size: 2x + 2 (quotes), +1 for space separator
                path_str.len() * 2 + 2 + 1
            })
            .sum()
    }

    /// Render the run command for a hypothetical job containing `files` and return
    /// its byte length. Returns `None` if rendering fails (e.g. the template
    /// references a variable not in the context).
    fn render_run_command_size(
        &self,
        original_job: &StepJob,
        files: &[PathBuf],
        base_tctx: &tera::Context,
    ) -> Option<usize> {
        let run_cmd = if original_job.check_first {
            self.check_first_cmd().map(|cmd| cmd.command())
        } else {
            self.run_cmd(original_job.run_type)
        }?;
        if run_cmd.is_empty() {
            return None;
        }

        let mut temp = StepJob::new(
            Arc::clone(&original_job.step),
            files.to_vec(),
            original_job.run_type,
        );
        temp.check_first = original_job.check_first;
        if let Some(wi) = original_job.workspace_indicator() {
            temp = temp.with_workspace_indicator(wi.clone());
        }
        let tctx = temp.tctx(base_tctx);
        run_cmd
            .render(&tctx, self.prefix.as_deref())
            .ok()
            .map(|command| command.execution_size())
    }

    /// Automatically batch jobs whose rendered run command would exceed the safe exec limit.
    ///
    /// Uses 50% of ARG_MAX as an aggregate safety margin and also respects
    /// platform-specific per-command limits such as Linux's MAX_ARG_STRLEN.
    /// Renders the actual run command with each candidate file subset; if the rendered command
    /// fits, no batching is performed. Otherwise binary-searches the largest batch size whose
    /// rendered command still fits.
    ///
    /// If rendering fails for any reason, falls back to estimating the size of the quoted
    /// file-list expansion — preserves the previous (purely size-based) behavior as a safety net.
    pub(crate) fn auto_batch_jobs(
        &self,
        jobs: Vec<StepJob>,
        base_tctx: &tera::Context,
    ) -> Result<Vec<StepJob>> {
        self.auto_batch_jobs_with_limit(jobs, base_tctx, None)
    }

    fn auto_batch_jobs_with_limit(
        &self,
        jobs: Vec<StepJob>,
        base_tctx: &tera::Context,
        safe_limit_override: Option<usize>,
    ) -> Result<Vec<StepJob>> {
        if self.stdin.is_some() {
            // stdin path doesn't pass files via argv; never auto-batch
            return Ok(jobs);
        }

        let mut batched_jobs = Vec::with_capacity(jobs.len());

        for job in jobs {
            if job.skip_reason.is_some() || job.files.is_empty() {
                batched_jobs.push(job);
                continue;
            }

            let run_cmd = if job.check_first {
                self.check_first_cmd().map(|cmd| cmd.command())
            } else {
                self.run_cmd(job.run_type)
            };
            let safe_limit = safe_limit_override.unwrap_or_else(|| {
                run_cmd
                    .map(|command| self.auto_batch_safe_limit(command))
                    .unwrap_or(*env::ARG_MAX / 2)
            });

            // Try render-based sizing first; fall back to byte estimation on render failure.
            let full_size = self
                .render_run_command_size(&job, &job.files, base_tctx)
                .unwrap_or_else(|| self.estimate_files_string_size(&job.files));

            if full_size <= safe_limit {
                batched_jobs.push(job);
                continue;
            }

            debug!(
                "{}: auto-batching {} files (rendered size: {} bytes, limit: {} bytes)",
                self.name,
                job.files.len(),
                full_size,
                safe_limit
            );

            // Size every chunk independently: later paths may be much longer
            // than the paths at the start of the job.
            let mut offset = 0;
            while offset < job.files.len() {
                let remaining = &job.files[offset..];
                let single_size = self
                    .render_run_command_size(&job, &remaining[..1], base_tctx)
                    .unwrap_or_else(|| self.estimate_files_string_size(&remaining[..1]));
                if single_size > safe_limit {
                    bail!(
                        "{}: rendered command for {} is {} bytes, exceeding the {}-byte command-line limit",
                        self.name,
                        remaining[0].display(),
                        single_size,
                        safe_limit
                    );
                }

                // Binary search the largest prefix of the remaining files that fits.
                let mut low = 1;
                let mut high = remaining.len();
                while low < high {
                    let mid = (low + high).div_ceil(2);
                    let test_size = self
                        .render_run_command_size(&job, &remaining[..mid], base_tctx)
                        .unwrap_or_else(|| self.estimate_files_string_size(&remaining[..mid]));
                    if test_size <= safe_limit {
                        low = mid;
                    } else {
                        high = mid - 1;
                    }
                }
                let batch_size = low;

                debug!("{}: using batch size of {} files", self.name, batch_size);

                let chunk = &remaining[..batch_size];
                let mut new_job = StepJob::new(Arc::clone(&job.step), chunk.to_vec(), job.run_type);
                // Preserve job-level state that isn't reconstructed by StepJob::new.
                new_job.check_first = job.check_first;
                new_job.skip_reason = job.skip_reason.clone();
                if let Some(wi) = job.workspace_indicator() {
                    new_job = new_job.with_workspace_indicator(wi.clone());
                }
                batched_jobs.push(new_job);
                offset += batch_size;
            }
        }

        Ok(batched_jobs)
    }
}

