    fn truncate_quoted_list_truncates_multiple_tokens() {
        let v = tera::Value::from("first.txt second.txt third.txt");
        assert_eq!(
            truncate_quoted_list(Some(&v)),
            Some("first.txt …".to_string())
        );
    }

