    fn truncate_quoted_list_preserves_quoted_first_token() {
        let v = tera::Value::from("'a b.txt' other.txt");
        assert_eq!(
            truncate_quoted_list(Some(&v)),
            Some("'a b.txt' …".to_string())
        );
    }

