    assert_success

    run cat argv.log
    assert_success
    assert_line --index 0 '$HOME'
    assert_line --index 1 '*'
    assert_line 'a b.txt'
    assert_line 'semi;colon.txt'
    assert_equal "${#lines[@]}" 4
}

